# Category: serverless_security

import boto3
import os
import logging

logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client('s3')
sns = boto3.client('sns')

def lambda_handler(event, context):
    try:
        # Extract the bucket name and file key from the event
        bucket_name = event['Records'][0]['s3']['bucket']['name']
        file_key = event['Records'][0]['s3']['object']['key']
        
        # Read image file from S3
        response = s3.get_object(Bucket=bucket_name, Key=file_key)
        image_data = response['Body'].read()

        # Process the image (placeholder for processing logic)
        processed_image_data = image_data  # No processing for MVP

        # Write the processed image back to S3
        output_bucket = os.environ['OUTPUT_BUCKET']
        output_key = f'processed_{file_key}'
        s3.put_object(Bucket=output_bucket, Key=output_key, Body=processed_image_data)

        # Send notification via SNS
        sns.publish(
            TopicArn=os.environ['SNS_TOPIC_ARN'],
            Message=f"Image {file_key} processed and saved as {output_key}.",
            Subject="Image Processing Notification"
        )

        logger.info(f"Successfully processed {file_key} and uploaded as {output_key}")

    except Exception as e:
        logger.error(f"Error processing the image: {e}")

